// // This module decrements a 3-bit binary counter on each clock cycle and resets to 7 when the reset signal is high.
module counter3bit (
    input clk,
    input rst,
    output reg [2:0] count
);always @(posedge clk or posedge rst) begin
    if (rst) begin
        count <= 3'b000;
    end else begin
        count <= count + 1;
    end
end

endmodule
